example.code:
queue: kind: redis-streams connection: redis://queue.internal:6379 consumer_group: video-workers workers: count: 8 concurrency: 5
providers: - {name: runway, model: gen-3-alpha, weight: 0.6, max_concurrent: 5} - {name: luma, model: dream-machine, weight: 0.4, max_concurrent: 3}
ffmpeg: enabled: true operations: [concat, overlay-watermark, transcode-h264-720p]
tenant_quotas: default_monthly_jobs: 100 default_monthly_usd: 50 vip_overrides: "tenant-x": {monthly_jobs: 1000, monthly_usd: 500}
cost_cap: global_monthly_usd: 2500 reject_at_pct: 95 alert_at_pct: 80
idempotency: window_hours: 24 store: redis
